const header=document.querySelector(".header-container"),logo=document.querySelector(".logo"),hamburgerBtn=document.getElementById("hamburger-btn"),drawer=document.getElementById("drawer"),drawerOverlay=document.getElementById("drawer-overlay"),drawerClose=document.getElementById("drawer-close"),drawerLinks=document.querySelectorAll(".drawer-link");let lastScroll=0;window.addEventListener("scroll",()=>{const e=window.scrollY;if(e===0){header.classList.remove("hide"),logo.style.height="90px",lastScroll=e;return}e>lastScroll?header.classList.add("hide"):(header.classList.remove("hide"),logo.style.height="55px"),lastScroll=e});function openDrawer(){drawer.classList.add("open"),drawerOverlay.classList.add("open"),document.body.style.overflow="hidden"}function closeDrawer(){drawer.classList.remove("open"),drawerOverlay.classList.remove("open"),document.body.style.overflow=""}hamburgerBtn.addEventListener("click",openDrawer),drawerClose.addEventListener("click",closeDrawer),drawerOverlay.addEventListener("click",closeDrawer),drawerLinks.forEach(e=>e.addEventListener("click",closeDrawer))